import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate, useLocation } from 'react-router-dom';
import { Send, Info, CheckCircle, ArrowLeft } from 'lucide-react';
import { MotionButton } from '../components/MotionButton';

export default function BarterRequest() {
  const navigate = useNavigate();
  const location = useLocation();
  const [isSent, setIsSent] = useState(false);
  
  // Captures the item passed from the Explore page
  const item = location.state?.item || { title: "Listing", user: "Community Member", wtk: 0 };

  const handleSubmit = (e) => {
    e.preventDefault();
    const message = e.target.message.value;

    const requestData = {
      id: Date.now(),
      itemTitle: item.title,
      toUser: item.user,
      wtkAmount: item.wtk,
      proposal: message,
      status: 'Pending',
      date: new Date().toLocaleDateString()
    };

    // Save request to global system state
    const existingRequests = JSON.parse(localStorage.getItem('barterRequests')) || [];
    localStorage.setItem('barterRequests', JSON.stringify([requestData, ...existingRequests]));

    setIsSent(true);
    setTimeout(() => navigate('/dashboard'), 2500);
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }} 
      animate={{ opacity: 1, y: 0 }} 
      className="max-w-xl mx-auto space-y-8 p-6 pt-10"
    >
      <button 
        onClick={() => navigate(-1)} 
        className="text-slate-400 font-bold flex items-center gap-2 hover:text-teal-600 transition-colors"
      >
        <ArrowLeft size={18}/> Back to Explore
      </button>

      <div className="bg-teal-600 p-10 rounded-[40px] text-white shadow-xl shadow-teal-600/20">
        <h2 className="text-3xl font-black tracking-tight">Initiate Barter</h2>
        <p className="opacity-80 font-medium mt-2">
          Requesting <span className="font-black italic">"{item.title}"</span> from {item.user}
        </p>
      </div>

      <div className="bg-white dark:bg-slate-900 p-8 rounded-[40px] border border-slate-100 dark:border-slate-800 shadow-sm space-y-6">
        <div className="p-5 bg-amber-50 dark:bg-amber-900/20 rounded-2xl flex gap-3 border border-amber-100 dark:border-amber-900/30">
          <Info className="text-amber-600 shrink-0" size={20} />
          <p className="text-[11px] text-amber-800 dark:text-amber-200 font-bold leading-relaxed">
            Note: Sending this request will notify the owner. {item.wtk} WTK tokens will be earmarked for this exchange.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Your Proposal</label>
            <textarea 
              name="message"
              required
              rows="5" 
              placeholder={`Hi ${item.user}, I'm interested in this. Would you be open to...`} 
              className="w-full p-6 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-3xl outline-none focus:ring-2 ring-teal-500 border-none transition-all font-medium" 
            />
          </div>

          <MotionButton className="w-full py-5 rounded-[24px] flex justify-center items-center gap-3 text-lg font-black shadow-lg shadow-teal-600/30">
            Send Barter Request <Send size={20} />
          </MotionButton>
        </form>
      </div>

      <AnimatePresence>
        {isSent && (
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            className="fixed inset-0 bg-white/90 dark:bg-slate-950/90 backdrop-blur-md z-[100] flex items-center justify-center"
          >
            <div className="text-center p-10">
              <div className="w-24 h-24 bg-teal-100 dark:bg-teal-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                <CheckCircle size={48} className="text-teal-600" />
              </div>
              <h3 className="text-4xl font-black text-slate-900 dark:text-white">Proposal Sent!</h3>
              <p className="text-slate-400 font-bold mt-2">Waiting for {item.user} to respond.</p>
              <div className="mt-8 w-48 bg-slate-100 dark:bg-slate-800 h-1.5 rounded-full mx-auto overflow-hidden">
                <motion.div 
                  initial={{ width: 0 }} 
                  animate={{ width: "100%" }} 
                  transition={{ duration: 2 }} 
                  className="h-full bg-teal-600" 
                />
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}
